solution_code:
#include <iostream>

int* copyToHeap(const int* values, int n)
{
    int* heap{ new int[n] };
    for (int i{ 0 }; i < n; ++i)
        heap[i] = values[i];
    return heap;
}

int main()
{
    int n{};
    std::cin >> n;

    int local[100]{};
    for (int i{ 0 }; i < n; ++i)
        std::cin >> local[i];

    int* copy{ copyToHeap(local, n) };

    for (int i{ 0 }; i < n; ++i)
    {
        if (i > 0)
            std::cout << ' ';
        std::cout << copy[i];
    }
    std::cout << '\n';

    delete[] copy;

    return 0;
}
